#include <stdio.h>
#include <stdlib.h>

// Node structure for polynomial term
struct PolyNode {
 int coeff; // Coefficient of the term
 int exp; // Exponent of the term
 struct PolyNode *next; // Pointer to next term
};

typedef struct PolyNode *PolyPtr;

// Create a new node
PolyPtr createNode(int coeff, int exp) {
 PolyPtr newNode = (PolyPtr)malloc(sizeof(struct PolyNode));
 if (newNode == NULL) {
 printf("Memory allocation failed!\n");
 exit(1);
 }
 newNode->coeff = coeff;
 newNode->exp = exp;
 newNode->next = NULL;
 return newNode;
}

// Insert term in descending order of exponent
void insertTerm(PolyPtr *head, int coeff, int exp) {
 if (coeff == 0) return;

 PolyPtr newNode = createNode(coeff, exp);

 // Case 1: Empty list
 if (*head == NULL) {
 *head = newNode;
 return;
 }

 // Case 2: Insert at beginning (highest exponent)
 if ((*head)->exp < exp) {
 newNode->next = *head;
 *head = newNode;
 return;
 }

 // Case 3: Find correct position
 PolyPtr current = *head;
 while (current->next != NULL && current->next->exp > exp) {
 current = current->next;
 }

 // Case 4: Same exponent exists - add coefficients
 if (current->next != NULL && current->next->exp == exp) {
 current->next->coeff += coeff;
 if (current->next->coeff == 0) {
 PolyPtr temp = current->next;
 current->next = temp->next;
 free(temp);
 }
 free(newNode);
 return;
 }

 // Insert in between
 newNode->next = current->next;
 current->next = newNode;
}

// Display polynomial
void display(PolyPtr poly) {
 if (poly == NULL) {
 printf("0\n");
 return;
 }

 int first = 1;
 PolyPtr current = poly;

 while (current != NULL) {
 if (!first && current->coeff > 0)
 printf(" + ");

 if (current->exp == 0)
 printf("%d", current->coeff);
 else if (current->exp == 1)
 printf("%dx", current->coeff);
 else
 printf("%dx^%d", current->coeff, current->exp);

 first = 0;
 current = current->next;
 }
 printf("\n");
}

// Add two polynomials using linked lists
PolyPtr addPolynomials(PolyPtr p1, PolyPtr p2) {
 PolyPtr result = NULL;
 PolyPtr current1 = p1;
 PolyPtr current2 = p2;

 while (current1 != NULL && current2 != NULL) {
 if (current1->exp > current2->exp) {
 insertTerm(&result, current1->coeff, current1->exp);
 current1 = current1->next;
 } else if (current1->exp < current2->exp) {
 insertTerm(&result, current2->coeff, current2->exp);
 current2 = current2->next;
 } else {
 // Same exponent
 int sum = current1->coeff + current2->coeff;
 if (sum != 0)
 insertTerm(&result, sum, current1->exp);
 current1 = current1->next;
 current2 = current2->next;
 }
 }

 // Copy remaining terms
 while (current1 != NULL) {
 insertTerm(&result, current1->coeff, current1->exp);
 current1 = current1->next;
 }
 while (current2 != NULL) {
 insertTerm(&result, current2->coeff, current2->exp);
 current2 = current2->next;
 }

 return result;
}

// Evaluate polynomial at given x
int evaluate(PolyPtr poly, int x) {
 int result = 0;
 PolyPtr current = poly;

 while (current != NULL) {
 result = result * x + current->coeff;
 current = current->next;
 }
 return result;
}

// Free polynomial memory
void freePolynomial(PolyPtr poly) {
 PolyPtr current = poly;
 while (current != NULL) {
 PolyPtr temp = current;
 current = current->next;
 free(temp);
 }
}

// Main function demonstrating linked list polynomial operations
int main() {
 PolyPtr p1 = NULL;
 PolyPtr p2 = NULL;
 PolyPtr sum = NULL;

 // Create P(x) = 3x^3 + 2x^2 + 5
 insertTerm(&p1, 3, 3);
 insertTerm(&p1, 2, 2);
 insertTerm(&p1, 5, 0);

 // Create Q(x) = 4x^2 + 3x + 1
 insertTerm(&p2, 4, 2);
 insertTerm(&p2, 3, 1);
 insertTerm(&p2, 1, 0);

 printf("P(x) = ");
 display(p1);

 printf("Q(x) = ");
 display(p2);

 // Addition
 sum = addPolynomials(p1, p2);
 printf("P(x) + Q(x) = ");
 display(sum);

 // Evaluation
 printf("\nEvaluation: P(2) = %d\n", evaluate(p1, 2));

 // Sparse polynomial example
 PolyPtr sparse = NULL;
 insertTerm(&sparse, 8, 1000); // High degree, sparse polynomial
 insertTerm(&sparse, 5, 2);
 insertTerm(&sparse, 10, 0);

 printf("\nSparse R(x) = ");
 display(sparse);

 // Free memory
 freePolynomial(p1);
 freePolynomial(p2);
 freePolynomial(sum);
 freePolynomial(sparse);

 return 0;
}

import java.util.*;

class Term {
 int coeff;
 int exp;

 Term(int coeff, int exp) {
 this.coeff = coeff;
 this.exp = exp;
 }

 @Override
 public String toString() {
 if (exp == 0) return coeff + "";
 if (exp == 1) return coeff + "x";
 return coeff + "x^" + exp;
 }
}

public class Polynomial {
 private List<Term> terms;

 public Polynomial() {
 terms = new ArrayList<>();
 }

 // Add term - handles combining like terms
 public void addTerm(int coeff, int exp) {
 if (coeff == 0) return;

 // Check if term with same exponent exists
 for (Term t : terms) {
 if (t.exp == exp) {
 t.coeff += coeff;
 if (t.coeff == 0) {
 terms.remove(t);
 }
 return;
 }
 }

 // Add new term and sort by exponent (descending)
 terms.add(new Term(coeff, exp));
 sortTerms();
 }

 private void sortTerms() {
 terms.sort((a, b) -> b.exp - a.exp);
 }

 // Create polynomial from array of coefficients
 public static Polynomial fromCoefficients(int[] coeffs) {
 Polynomial poly = new Polynomial();
 for (int i = 0; i < coeffs.length; i++) {
 if (coeffs[i] != 0) {
 poly.addTerm(coeffs[i], i);
 }
 }
 return poly;
 }

 // Display polynomial
 public void display() {
 if (terms.isEmpty()) {
 System.out.println("0");
 return;
 }

 StringBuilder sb = new StringBuilder();
 for (int i = 0; i < terms.size(); i++) {
 Term t = terms.get(i);
 if (i > 0 && t.coeff > 0) {
 sb.append(" + ");
 }
 sb.append(t.toString());
 }
 System.out.println(sb.toString());
 }

 // Add two polynomials
 public static Polynomial add(Polynomial p1, Polynomial p2) {
 Polynomial result = new Polynomial();
 int i = 0, j = 0;

 while (i < p1.terms.size() && j < p2.terms.size()) {
 Term t1 = p1.terms.get(i);
 Term t2 = p2.terms.get(j);

 if (t1.exp > t2.exp) {
 result.addTerm(t1.coeff, t1.exp);
 i++;
 } else if (t1.exp < t2.exp) {
 result.addTerm(t2.coeff, t2.exp);
 j++;
 } else {
 result.addTerm(t1.coeff + t2.coeff, t1.exp);
 i++;
 j++;
 }
 }

 // Copy remaining terms
 while (i < p1.terms.size()) {
 result.addTerm(p1.terms.get(i).coeff, p1.terms.get(i).exp);
 i++;
 }
 while (j < p2.terms.size()) {
 result.addTerm(p2.terms.get(j).coeff, p2.terms.get(j).exp);
 j++;
 }

 return result;
 }

 // Multiply two polynomials
 public static Polynomial multiply(Polynomial p1, Polynomial p2) {
 Polynomial result = new Polynomial();

 for (Term t1 : p1.terms) {
 for (Term t2 : p2.terms) {
 int newCoeff = t1.coeff * t2.coeff;
 int newExp = t1.exp + t2.exp;
 result.addTerm(newCoeff, newExp);
 }
 }

 return result;
 }

 // Evaluate polynomial using Horner's method
 public int evaluate(int x) {
 // Sort by exponent ascending for Horner's method
 List<Term> sorted = new ArrayList<>(terms);
 sorted.sort(Comparator.comparingInt(t -> t.exp));

 int result = 0;
 for (Term t : sorted) {
 result = result * x + t.coeff;
 }
 return result;
 }

 // Get degree of polynomial
 public int getDegree() {
 if (terms.isEmpty()) return 0;
 return terms.get(0).exp;
 }

 // Main method for demonstration
 public static void main(String[] args) {
 // Example 1: P(x) = 3x^3 + 2x^2 + 5
 Polynomial p1 = new Polynomial();
 p1.addTerm(3, 3);
 p1.addTerm(2, 2);
 p1.addTerm(5, 0);

 // Example 2: Q(x) = 4x^2 + 3x + 1
 Polynomial p2 = new Polynomial();
 p2.addTerm(4, 2);
 p2.addTerm(3, 1);
 p2.addTerm(1, 0);

 System.out.print("P(x) = ");
 p1.display();

 System.out.print("Q(x) = ");
 p2.display();

 // Addition
 Polynomial sum = Polynomial.add(p1, p2);
 System.out.print("P(x) + Q(x) = ");
 sum.display();

 // Multiplication
 Polynomial product = Polynomial.multiply(p1, p2);
 System.out.print("P(x) * Q(x) = ");
 product.display();

 // Evaluation
 System.out.println("P(2) = " + p1.evaluate(2));

 // Coefficient array representation example
 System.out.println("\n--- Coefficient Array Demo ---");
 int[] coeffs = {5, 0, 2, 3}; // Represents 3x^3 + 2x^2 + 5
 Polynomial p3 = Polynomial.fromCoefficients(coeffs);
 System.out.print("From array [5,0,2,3]: P(x) = ");
 p3.display();

 // Sparse polynomial example
 System.out.println("\n--- Sparse Polynomial ---");
 Polynomial sparse = new Polynomial();
 sparse.addTerm(8, 1000);
 sparse.addTerm(5, 2);
 sparse.addTerm(10, 0);
 System.out.print("R(x) = ");
 sparse.display();
 System.out.println("Degree: " + sparse.getDegree());
 System.out.println("R(1) = " + sparse.evaluate(1));
 }
}
